                        // lbFwdDiff2.Text = Math.Abs(MeasureData2.ValueLvdt - DiffStartTmp2_1).ToString("F2"); // 원본 - 잘못된 매칭
                        // lbBwdDiff2.Text = Math.Abs(MeasureData2.ValueLvdt - DiffStartTmp2_1).ToString("F2"); // 현재값 표시 (원복귀로 작게 나올 수 있음)
