                case 29: // 서보 알람 뜨면
                    if (PLCData2.PlcValueBit[8, 1] == true || PLCData2.PlcValueBit[10, 1] == true)
                    {
                        PLCData2.SetPlcBit(9, 7, false); //1축 알람 리셋
                        PLCData2.SetPlcBit(9, 3, true); //1축 알람 리셋
                        PLCData2.SetPlcBit(11, 3, true); //2축 알람 리셋
                        tmrWatch2.Restart();
                        wStep2++;
                    }
                    else
                    {
                        wStep2 = 32;
                    }
