                               lbFwdDiffMeasure2.Text, lbBwdDiffMeasure2.Text,
                               lbTotalDiffMeasure2.Text, CheckLabelStatus(lbTotalDiffMeasure2));
                    wStep2++;
                    break;

                case 50:

                    if (lbReclFwdMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbReclBwdMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbLeverMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbTotalDiffMeasure2.BackColor == System.Drawing.Color.Blue)
                    {
                        PlaySound("DINGDONG.wav");
                        BarcodePrint2();
                        Logger.Log("[2] 바코드 출력");
                        GlobalValues.OkCount++;
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    else
                    {
                        BarcodePrintNg2();
                        PlaySound("NG.wav");
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    wStep2 = 51;
                    break;

                case 51:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        wStep2 = 0;
                    }
                    break;

            }

        }


