        private void ResetReclTq1() => ResetTorque(SerialReclTq1, "ReclTq1");
        private void ResetReclTq2() => ResetTorque(SerialReclTq2, "ReclTq2");
        private void ResetTorque(SerialPort sp, string name)
        {
            try
            {
                if (sp.IsOpen)
                {
                    sp.Write("1Z");
                    Logger.Log($"[{name}] 리셋 명령 전송됨");
                }
                else
                {
                    Logger.Log($"[{name}] 포트가 열려있지 않음");
                }
            }
            catch (Exception ex)
            {
                Logger.Log($"[{name}] 리셋 중 오류: {ex.Message}");
            }
        }

