        {
            try
            {
                using (var conn = new OleDbConnection(GlobalValues.gConString_Record))
                {
                    conn.Open();
                    string query = @"
                INSERT INTO Table1 (
                    WorkDate, WorkTime, ScanBarcode, PArtNo,
                    ReclFWdTq, ReclFWdTqDec,
                    ReclBwdTq, ReclBwdTqDec,
                    LeverTq, LeverTqDec,
