        private void workTimer1_Tick(object sender, EventArgs e)
        {
            lbStep1.Text = $"[{wStep1.ToString()}][{wRstStep1.ToString()}]";

            if (PLCData1.PlcValueBit[0, 1] == true && wRstStep1 == 0) //리셋 스위치
            {
                wRstStep1 = 0.1;
            }

            switch (wRstStep1)
            {
                case 0:
                    break;

                case 0.1:
                    wStep1 = 0;
                    tmrRstWatch1.Restart();
                    wRstStep1 = 0.2;
                    break;

                case 0.2:
                    if (PLCData1.PlcValueBit[0, 1] == true)
                    {
                        if (tmrRstWatch1.ElapsedMilliseconds > 1000)
                        {
                            PLCData1.FlagRecvAll = true;
                            Logger.Log("[1] 리셋 조건 발동");
                            wRstStep1 = 1;
                        }
                    }
                    else
                    {
                        wRstStep1 = 0;
                    }
                    break;

                case 1: //모든 시그널 클리어
                    for (int word = 0; word <= 7; word++)
                    {
                        for (int bit = 0; bit <= 15; bit++)
                        {
                            PLCData1.SetPlcBit(word, bit, false);
                        }
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData1.SetPlcBit(9, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData1.SetPlcBit(11, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData1.SetPlcBit(12, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData1.SetPlcBit(13, bit, false);
                    }
                    wRstStep1++;
                    break;

                case 2:
                    PLCData1.SetPlcBit(9, 1, false);
                    PLCData1.SetPlcBit(9, 2, false);
                    PLCData1.SetPlcBit(4, 9, true); //클램프 상승
                    Logger.Log("[1] 클램프 상승");
                    PLCData1.SetPlcBit(4, 10, true); //클램프 후진
                    Logger.Log("[1] 클램프 후진");
                    PLCData1.SetPlcBit(4, 13, true); //LVDT 후진
                    Logger.Log("[1] LVDT 후진");
                    tmrWatch1.Restart();
                    wRstStep1++;
                    break;

                case 3:
                    if (PLCData1.PlcValueBit[0, 6] == true)
                    {
                        PLCData1.SetPlcBit(4, 9, false); //클램프 상승
                    }
                    if (PLCData1.PlcValueBit[0, 8] == true)
                    {
                        PLCData1.SetPlcBit(4, 10, false); //클램프 후진
                    }
                    if (PLCData1.PlcValueBit[0, 11] == true)
                    {
                        PLCData1.SetPlcBit(4, 13, false); //LVDT 후진
                    }
                    if (PLCData1.PlcValueBit[0, 6] == true &&
                        PLCData1.PlcValueBit[0, 8] == true &&
                        PLCData1.PlcValueBit[0, 11] == true)
                    {
                        Logger.Log("[1] 클램프 상승 센서 받음");
                        Logger.Log("[1] 클램프 후진 센서 받음");
                        Logger.Log("[1] LVDT 후진 센서 받음");
                        tmrWatch1.Stop();
                        wRstStep1++;
                    }
                    break;

                case 4:
                    PLCData1.SetPlcBit(9, 9, true); //1축 서보 온
                    PLCData1.SetPlcBit(11, 9, true);//2축 서보 온
                    PLCData1.SetPlcBit(9, 3, true); //1축 알람 리셋
                    PLCData1.SetPlcBit(11, 3, true);//2축 알람 리셋
                    PLCData1.SetPlcBit(9, 6, true); //1축 수동 ON
                    PLCData1.SetPlcBit(11, 6, true);//2축 수동 ON                 
                    PLCData1.SetPlcBit(9, 5, false); //1축 자동 OFF
                    PLCData1.SetPlcBit(11, 5, false);//2축 자동 OFF                    
                    wRstStep1++;
                    break;

                case 5:
                    if (PLCData1.PlcValueBit[8, 1] == false && PLCData1.PlcValueBit[10, 1] == false &&
                        PLCData1.PlcValueBit[8, 7] == true && PLCData1.PlcValueBit[10, 7] == true &&
                        PLCData1.PlcValueBit[8, 4] == true && PLCData1.PlcValueBit[10, 4] == true)
                    {
                        wRstStep1++;
                    }
                    break;

                case 6:
                    PLCData1.SetPlcBit(9, 1, true); //1축 CCW
                    PLCData1.SetPlcBit(11, 1, true);//2축 CCW
                    tmrWatch1.Restart();
                    PLCData1.Servo1JogSpd = 1000;
                    PLCData1.ServoSet();
                    wRstStep1++;
                    break;

                case 7:
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        PLCData1.SetPlcBit(9, 1, false); //1축 CCW
                        PLCData1.SetPlcBit(11, 1, false);//2축 CCW
                        tmrWatch1.Stop();
                        wRstStep1++;
                    }
                    break;

                case 8:
                    if (PLCData1.PlcValueBit[9, 1] == false && PLCData1.PlcValueBit[11, 1] == false)
                    {
                        PLCData1.SetPlcBit(9, 4, true); //1축 홈 ON 
                        Logger.Log("[1] 1축 원위치 시작");
                        tmrWatch1.Restart();
                        wRstStep1 = 8.1;
                    }
                    break;

                case 8.1:
                    if (tmrWatch1.ElapsedMilliseconds > 500)
                    {
                        tmrWatch1.Stop();
                        PLCData1.SetPlcBit(9, 4, false); //1축 홈 OFF                                          
                        wRstStep1 = 9;
                    }
                    break;


                case 9:
                    if (PLCData1.PlcValueBit[8, 12] == true) // 1축 홈포지션 완료
                    {
                        Logger.Log("[1] 1축 원위치 완료");
                        PLCData1.SetPlcBit(9, 4, false); //1축 홈 OFF
                        tmrRstWatch1.Restart();
                        wRstStep1 = 9.1;
                    }
                    break;

                case 9.1:
                    if (tmrRstWatch1.ElapsedMilliseconds > 500)
                    {
                        tmrRstWatch1.Stop();
                        wRstStep1 = 10;
                    }
                    break;

                case 10:

                    PLCData1.SetPlcBit(11, 4, true); //2축 홈 ON
                    Logger.Log("[1] 2축 원위치 시작");
                    tmrRstWatch1.Restart();
                    wRstStep1 = 10.1;
                    break;

                case 10.1:
                    if (tmrRstWatch1.ElapsedMilliseconds > 500)
                    {
                        PLCData1.SetPlcBit(11, 4, false); //2축 홈 OFF
                        tmrRstWatch1.Stop();
                        wRstStep1 = 11;
                    }
                    break;

                case 11:
                    if (PLCData1.PlcValueBit[10, 12] == true) // 2축 홈포지션 완료
                    {
                        Logger.Log("[1] 2축 원위치 완료");
                        PLCData1.SetPlcBit(11, 4, false); //2축 홈 OFF
                        tmrRstWatch1.Restart();
                        wRstStep1 = 11.1;
                    }
                    break;

                case 11.1:
                    if (tmrRstWatch1.ElapsedMilliseconds > 1500)
                    {
                        wRstStep1 = 12;
                    }
                    break;

                case 12:
                    PLCData1.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData1.SetPlcBit(11, 6, false); //2축 수동 OFF
                    PLCData1.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData1.SetPlcBit(11, 5, true); //1축 자동 ON
                    wRstStep1++;
                    break;

                case 13:
                    if (PLCData1.PlcValueBit[8, 3] == true && PLCData1.PlcValueBit[10, 3] == true) //자동 
                    {
                        Logger.Log("[1] 1축 1번 포지션 이동 시작");
                        PLCData1.SetPlcBit(12, 0, true); //1축 1번 포지션ㄱㄱ
                        wRstStep1++;
                    }
                    break;

                case 14:
                    if (PLCData1.PlcValueBit[14, 0] == true) //1축 1번 완료 
                    {
                        Logger.Log("[1] 1축 1번 포지션 이동 완료");
                        PLCData1.SetPlcBit(12, 0, false);
                        wRstStep1++;
                    }
                    break;

                case 15:
                    Logger.Log("[1] 2축 1번 포지션 이동 시작");
                    PLCData1.SetPlcBit(13, 0, true); //2축 1번 포지션ㄱㄱ
                    wRstStep1++;
                    break;

                case 16:
                    if (PLCData1.PlcValueBit[15, 0] == true) //2축 1번 완료 
                    {
                        Logger.Log("[1] 2축 1번 포지션 이동 완료");
                        PLCData1.SetPlcBit(13, 0, false);
                        wRstStep1++;
                    }
                    break;

                case 17:
                    InitControl1();
                    PLCData1.FlagRecvAll = false;
                    wRstStep1 = 0;
                    Logger.Log("[1] 리셋 완료");
                    break;

            }

            switch (wStep1)
            {
                case 0:

                    if (MeasureData1.TargetScan == "0")
                    {
                        if (PLCData1.PlcValueBit[0, 0] == true) //작업 시작
                        {
                            Logger.Log("[1] 작업 시작(바코드 미사용)");
                            string tmppart = lbLPartNo1.Text;
                            string tmpbarcode = lbBarcode1.Text;
                            InitControl1();
                            lbLPartNo1.Text = tmppart;
                            lbBarcode1.Text = tmpbarcode;
                            lbReclFwdSpec1.Text = $"{MeasureData1.ReclineForwardTorqueMin.ToString()} ~ {MeasureData1.ReclineForwardTorqueMax.ToString()} Nm";
                            lbReclBwdSpec1.Text = $"{MeasureData1.ReclineForwardTorqueMin.ToString()} ~ {MeasureData1.ReclineForwardTorqueMax.ToString()} Nm";
                            lbLeverSpec1.Text = $"{MeasureData1.LeverTorqueMin.ToString()} ~ {MeasureData1.LeverTorqueMax.ToString()} Nm";

                            DiffSpec1.Text = $"{MeasureData1.SpecDiff.ToString()}";

                            PLCData1.SetPlcBit(4, 8, true); //클램프 하강
                            Logger.Log("[1] 클램프 하강 시작");
                            tmrWatch1.Restart();
                            PLCData1.FlagRecvAll = false;
                            wStep1++;
                        }
                    }
                    else
                    {
                        if (PLCData1.PlcValueBit[0, 0] == true && lbLPartNo1.Text != "" && lbBarcode1.BackColor == System.Drawing.Color.Blue) //작업 시작
                        {
                            Logger.Log("[1] 작업 시작(바코드 사용)");
                            string tmppart = lbLPartNo1.Text;
                            string tmpbarcode = lbBarcode1.Text;
                            InitControl1();
                            lbLPartNo1.Text = tmppart;
                            lbBarcode1.Text = tmpbarcode;
                            lbReclFwdSpec1.Text = $"{MeasureData1.ReclineForwardTorqueMin.ToString()} ~ {MeasureData1.ReclineForwardTorqueMax.ToString()} Nm";
                            lbReclBwdSpec1.Text = $"{MeasureData1.ReclineForwardTorqueMin.ToString()} ~ {MeasureData1.ReclineForwardTorqueMax.ToString()} Nm";
                            lbLeverSpec1.Text = $"{MeasureData1.LeverTorqueMin.ToString()} ~ {MeasureData1.LeverTorqueMax.ToString()} Nm";

                            DiffSpec1.Text = $"{MeasureData1.SpecDiff.ToString()}";

                            PLCData1.SetPlcBit(4, 8, true); //클램프 하강
                            Logger.Log("[1] 클램프 하강 시작");
                            tmrWatch1.Restart();
                            PLCData1.FlagRecvAll = false;
                            wStep1++;
                        }
                    }
                    break;

                case 1:
                    if (PLCData1.PlcValueBit[0, 7] == true)
                    {
                        Logger.Log("[1] 클램프 하강 완료");
                        PLCData1.SetPlcBit(4, 8, false); //클램프 하강
                        PLCData1.SetPlcBit(4, 11, true); //클램프 전진
                        Logger.Log("[1] 클램프 전진 시작");
                        wStep1++;
                    }
                    break;

                case 2:
                    if (PLCData1.PlcValueBit[0, 9] == true) //클램프 전진 완료
                    {
                        Logger.Log("[1] 클램프 전진 완료");
                        PLCData1.SetPlcBit(4, 11, false);
                        tmrWatch1.Restart();
                        wStep1++;
                    }
                    break;

                case 3:
                    Logger.Log("[1] 토크 제로 (레버+리클)");
                    ResetLeverTq1();
                    ResetReclTq1();
                    wStep1++;
                    tmrWatch1.Restart();
                    break;

                case 4:
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch1.Stop();
                        wStep1++;
                    }
                    break;

                case 5:
                    PLCData1.SetPlcBit(13, 1, true); //2축 2 포지션 이동 레버해제
                    Logger.Log("[1] 2축 2번 포지션 이동 시작");
                    measureStartTime1 = DateTime.Now;
                    timeList1.Clear();
                    valueList1.Clear();
                    tmrWatch1.Restart();
                    tmpMax1 = 0;
                    _csv1.Clear();
                    wStep1++;
                    break;

                case 6:

                    double elapsedSeconds = tmrWatch1.Elapsed.TotalSeconds;
                    if (tmpMax1 < MeasureData1.ValueLeverTq * MeasureData1.LeverTorqueTolerance) tmpMax1 = MeasureData1.ValueLeverTq * MeasureData1.LeverTorqueTolerance; //최대값 갱신                                                                   
                    ClassZedGraph.DrawGraph(PlotLever1, MeasureData1.ValueLeverTq * MeasureData1.LeverTorqueTolerance, elapsedSeconds);

                    _csv1.Add(elapsedSeconds, MeasureData1.ValueLeverTq * MeasureData1.LeverTorqueTolerance);

                    if (PLCData1.PlcValueBit[15, 1] == true) //2축 2 포지션 완료
                    {
                        tmpsave1 = DateTime.Now.ToString("yyMMddHHmmss") + Lot1 + lbLPartNo1.Text;
                        _csv1.Save($"{tmpsave1}_Lever_Torque");
                        Logger.Log("[1] RAW 저장 완료");
                        Logger.Log("[1] 2축 2번 포지션 이동 완료");
                        lbLeverMeasure1.Text = tmpMax1.ToString("F1");
                        PLCData1.SetPlcBit(13, 1, false);
                        wStep1++;
                    }
                    break;

                case 7:
                    JudgeAndSetLabel(MeasureData1.LeverTorqueMin, MeasureData1.LeverTorqueMax, tmpMax1, lbLeverMeasure1);
                    wStep1++;
                    break;

                case 8:
                    if (MeasureData1.BurnishingCount > 0)
                    {
                        bCount1 = 0;
                        wStep1 = 8.1;
                    }
                    else
                    {
                        wStep1++;
                    }
                    break;

                case 8.1: //버니싱
                    Logger.Log($"[1] 버니싱 시작 {bCount1 + 1.ToString()}");
                    Logger.Log("[1] 1축 4번 포지션 이동 시작");
                    PLCData1.SetPlcBit(12, 3, true);//1축 4 포지션
                    wStep1 = 8.2;
                    break;

                case 8.2:
                    if (PLCData1.PlcValueBit[14, 3] == true) //완료
                    {
                        Logger.Log("[1] 1축 4번 포지션 이동 완료");
                        PLCData1.SetPlcBit(12, 3, false);
                        wStep1 = 8.3;
                    }
                    break;

                case 8.3:
                    Logger.Log("[1] 1축 5번 포지션 이동 시작");
                    PLCData1.SetPlcBit(12, 4, true);//1축 5 포지션
                    wStep1 = 8.4;
                    break;

                case 8.4:
                    if (PLCData1.PlcValueBit[14, 4] == true) //완료
                    {
                        Logger.Log("[1] 1축 5번 포지션 이동 완료");
                        PLCData1.SetPlcBit(12, 4, false);
                        wStep1 = 8.5;
                    }
                    break;

                case 8.5:
                    bCount1++;
                    if (bCount1 >= MeasureData1.BurnishingCount)
                    {
                        Logger.Log("[1] 버니싱 완료");
                        wStep1 = 9;
                    }
                    else
                    {
                        wStep1 = 8.1; //다시 버니싱
                    }
                    break;

