                            // );
                        }

                        // 유격 로그는 CCW 복귀 완료 후 닫음 (case 37.7)
                        // CloseDiffLog2();

                        tmrWatch2.Restart();
                        wStep2++;
                    }
                    }
                    break;

                case 36:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        DiffFwdTmp2 = MeasureData2.ValueLvdt;
                        tmrWatch2.Stop();
                        wStep2++;
                    }
                    break;

                case 37:

                    // lbBwdDiff2.Text = Math.Abs((MeasureData2.ValueLvdt) - DiffStartTmp2_2).ToString("F2"); // 원본 - 잘못된 매칭
                    // lbFwdDiff2.Text = Math.Abs((MeasureData2.ValueLvdt) - DiffStartTmp2_2).ToString("F2"); // 현재값 표시 (원복귀로 작게 나올 수 있음)
                    lbFwdDiff2.Text = MaxDiffFwd2.ToString("F2"); // CW(전진) 최대 변위 표시
                    lbTotalDiff2.Text = (Double.Parse(lbBwdDiff2.Text) + Double.Parse(lbFwdDiff2.Text)).ToString("F2");

                    double tmpf, tmpb, tmps, fval, bval, sval;

                    tmpf = Math.Abs(Double.Parse(lbFwdDiff2.Text));
                    tmpb = Math.Abs(Double.Parse(lbBwdDiff2.Text));
                    tmps = Math.Abs(Double.Parse(lbTotalDiff2.Text));

                    fval = Math.Floor((tmpf / 300) * (180 / 3.14) * 100) / 100.0;
                    bval = Math.Floor((tmpb / 300) * (180 / 3.14) * 100) / 100.0;
                    sval = Math.Floor((tmps / 300) * (180 / 3.14) * 100) / 100.0;

                    lbFwdDiffMeasure2.Text = fval.ToString("F2");
                    lbBwdDiffMeasure2.Text = bval.ToString("F2");
                    lbTotalDiffMeasure2.Text = (fval + bval).ToString("F2");

                    JudgeAndSetLabelF2(0, MeasureData2.SpecDiff, fval + bval, lbTotalDiffMeasure2);
                    // 속도 복원은 CCW 복귀 완료 후 case 38에서 수행
                    // PLCData2.Servo1JogSpd = tmpBeforeSpeed2;
                    // PLCData2.FlagRecvAll = true;
                    // PLCData2.ServoSet();
                    WriteDiffLog2(37, $"SPEED_KEEP_DIFF: DiffSpeed={PLCData2.DiffSpeed}, CurrentSpd={PLCData2.Servo1JogSpd}");
                    WriteDebugLog2(37, $"RESULT:FwdDiff={MaxDiffFwd2:F4},BwdDiff={MaxDiffBwd2:F4},fval={fval:F4},bval={bval:F4}");
                    wStep2 = 37.1;
                    break;

                case 37.1: // 알람 확인 및 리셋 (무조건 리셋 후 진행)
                    WriteDiffLog2(37.1, "ALARM_CHECK");
                    PLCData2.SetPlcBit(9, 7, false); //1축 수동 정지 지령 해제
                    PLCData2.SetPlcBit(9, 3, true); //1축 알람 리셋
                    PLCData2.SetPlcBit(11, 3, true); //2축 알람 리셋
                    WriteDiffLog2(37.1, "ALARM_RESET_ON");
                    tmrWatch2.Restart();
                    wStep2 = 37.2;
                    break;

                case 37.2: // 알람 리셋 대기 (1초)
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch2.Stop();
                        PLCData2.SetPlcBit(9, 3, false); //1축 알람 리셋 OFF
                        PLCData2.SetPlcBit(11, 3, false); //2축 알람 리셋 OFF
                        WriteDiffLog2(37.2, "ALARM_RESET_OFF");
                        wStep2 = 37.3;
                    }
                    break;

                case 37.3: // 알람 해제 확인
                    if (PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false)
                    {
                        WriteDiffLog2(37.3, "ALARM_CLEARED");
                        tmrWatch2.Restart();
                        wStep2 = 37.4; // 딜레이 후 CCW 복귀
                    }
                    else
                    {
                        WriteDiffLog2(37.3, "ALARM_STILL_ON");
                        wStep2 = 37.1; // 알람 아직 있으면 다시 리셋
                    }
                    break;

                case 37.4: // CCW 복귀 전 딜레이 (1초 대기)
                    WriteDiffLog2(37.4, "CCW_RETURN_DELAY");
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        Logger.Log("[2] CCW 복귀 딜레이 완료");
                        WriteDiffLog2(37.4, "CCW_RETURN_DELAY_END");
                        wStep2 = 37.5;
                    }
                    break;

                case 37.5: // CCW 복귀 측정 시작 (토크 0까지)
                    Logger.Log("[2] CCW 복귀 측정 시작");
                    WriteDiffLog2(37.5, "CCW_RETURN_START");
                    WriteDebugLog2(37.5, "CCW_RETURN_START");
                    PLCData2.SetPlcBit(9, 6, true);  // 1축 수동 ON
                    WriteDiffLog2(37.5, "PLC_MANUAL_ON");
                    PLCData2.SetPlcBit(9, 7, false); // 1축 수동 정지 지령 해제
                    WriteDiffLog2(37.5, "PLC_STOP_OFF");
                    PLCData2.SetPlcBit(9, 1, false); // 1축 CW OFF
                    WriteDiffLog2(37.5, "PLC_CW_OFF");
                    PLCData2.SetPlcBit(9, 2, true);  // 1축 CCW ON
                    WriteDiffLog2(37.5, "PLC_CCW_ON");
                    // diff2CwEndX, diff2CwEndLvdt는 case 35 CW_END에서 이미 저장됨
                    // 복귀선 첫 점을 CW 마지막 좌표에 찍어서 연결
                    ClassZedGraph.DrawGraphLine(PlotDiff2, diff2LastX, diff2LastY, 2);
                    tmrWatch2.Restart();
                    wStep2 = 37.6;
                    break;

                case 37.6: // CCW 복귀 - 토크 0까지 이동
                    {
                        double xReturn = diff2CwEndX + (MeasureData2.ValueLvdt - diff2CwEndLvdt);
                        double yReturn = tmpNum2 * -1 * MeasureData2.ValueReclTq;

                        // 토크가 음수(CW방향)일 때만 복귀 곡선 그리기
                        if (yReturn <= 0)
                        {
                            ClassZedGraph.DrawGraphLine(PlotDiff2, xReturn, yReturn, 2); // 파랑 선 (복귀)
                            diff2LastX = xReturn;
                            diff2LastY = yReturn;
                        }
                        WriteDiffLog2(37.6, "CCW_RETURN_MEASURE");
                        WriteDebugLog2(37.6, "CCW_RETURN_MEASURE", xReturn, yReturn);

                        // 토크가 0 근처에 도달하면 완료
                        if (Math.Abs(MeasureData2.ValueReclTq) < 0.5)
                        {
                            ClassZedGraph.DrawGraphLine(PlotDiff2, 0, 0, 2); // 그래프 원점으로 루프 닫기
                            Logger.Log("[2] CCW 복귀 완료 (토크 0 도달)");
                            WriteDiffLog2(37.6, "CCW_RETURN_END");
                            PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                            WriteDiffLog2(37.6, "PLC_CCW_OFF");
                            PLCData2.SetPlcBit(9, 7, true);  // 수동 정지
                            WriteDiffLog2(37.6, "PLC_STOP_ON");
                            CloseDiffLog2();
                            CloseDebugLog2();
                            wStep2 = 38;
                        }
                        // 타임아웃: 15초 내 토크 0 미도달 시 강제 완료
                        else if (tmrWatch2.Elapsed.TotalSeconds > 15)
                        {
                            Logger.Log("[2] CCW 복귀 타임아웃 - 강제 완료");
                            WriteDiffLog2(37.6, "CCW_RETURN_TIMEOUT");
                            WriteDebugLog2(37.6, "CCW_RETURN_TIMEOUT", xReturn, yReturn);
                            PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                            PLCData2.SetPlcBit(9, 7, true);  // 수동 정지
                            CloseDiffLog2();
                            CloseDebugLog2();
                            wStep2 = 38;
                        }
                    }
                    break;

                case 38:
                    // 속도 복원 (원래 속도로)
                    WriteDiffLog2(38, $"SPEED_RESTORE: BeforeSpeed={tmpBeforeSpeed2}, CurrentSpd={PLCData2.Servo1JogSpd}");
                    PLCData2.Servo1JogSpd = tmpBeforeSpeed2;
                    PLCData2.FlagRecvAll = true;
                    PLCData2.ServoSet();

                    PLCData2.SetPlcBit(9, 7, false); //1축 수동 정지 지령
                    PLCData2.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData2.SetPlcBit(11, 5, true); //2축 자동 ON
                    PLCData2.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData2.SetPlcBit(11, 6, false); //2축 수동 OFF
                    _csv2.Save($"{tmpsave2}_Diff");
                    wStep2++;
                    break;

                case 39:
                    Logger.Log("[2] LVDT 후진 시작");
                    PLCData2.SetPlcBit(4, 13, true); //LVDT 후진
                    wStep2++;
                    break;

                case 40:
                    if (PLCData2.PlcValueBit[0, 11] == true) //후진 확인
                    {
                        Logger.Log("[2] LVDT 후진 완료");
                        PLCData2.SetPlcBit(4, 13, false);
                        PLCData2.FlagRecvAll = false;
                        wStep2++;
                    }
                    break;

                case 41:
                    Logger.Log("[2] 2축 2번 포지션 이동 시작");
                    PLCData2.SetPlcBit(13, 1, true); //2축 2번 포지션,레버 해제
                    wStep2++;
                    break;

                case 42:
                    if (PLCData2.PlcValueBit[15, 1] == true)
                    {
                        Logger.Log("[2] 2축 2번 포지션 이동 완료");
                        PLCData2.SetPlcBit(13, 1, false); //레버 해제 완료
                        wStep2++;
                    }
                    break;

                case 43:
                    Logger.Log("[2] 1축 1번 포지션 이동 시작");
                    PLCData2.SetPlcBit(12, 0, true); //1축 1번 포지션
                    wStep2++;
                    break;

                case 44:
                    if (PLCData2.PlcValueBit[14, 0] == true)
                    {
                        Logger.Log("[2] 1축 1번 포지션 이동 완료");
                        PLCData2.SetPlcBit(12, 0, false);
                        wStep2++;
                    }
                    break;

                case 45:
                    Logger.Log("[2] 2축 1번 포지션 이동 시작");
                    PLCData2.SetPlcBit(13, 0, true); //2축 1번 포지션,레버 원위치
                    wStep2++;
                    break;

                case 46:
                    if (PLCData2.PlcValueBit[15, 0] == true)
                    {
                        Logger.Log("[2] 2축 1번 포지션 이동 완료");
                        PLCData2.SetPlcBit(13, 0, false); //레버 해제 완료
                        wStep2++;
                    }
                    break;

                case 47:

                    Logger.Log("[2] 클램프 해제");
                    PLCData2.SetPlcBit(4, 9, true); //클램프 상승
                    PLCData2.SetPlcBit(4, 10, true); //클램프 후진
                    tmrRstWatch2.Restart();
                    wStep2++;
                    break;

                case 48:
                    if (PLCData2.PlcValueBit[0, 6] == true) //클램프 상승
                    {
                        PLCData2.SetPlcBit(4, 9, false); //클램프 상승
                    }
                    if (PLCData2.PlcValueBit[0, 8] == true) //클램프 후진
                    {
                        PLCData2.SetPlcBit(4, 10, false); //클램프 후진
                    }
                    if (PLCData2.PlcValueBit[0, 6] == true && PLCData2.PlcValueBit[0, 8] == true)
                    {
                        wStep2++;
                    }
                    break;

                case 49:
                    Logger.Log("[2] 데이터 저장");
                    InsertData(lbBarcode2.Text, lbLPartNo2.Text,
                               lbReclFwdMeasure2.Text, CheckLabelStatus(lbReclFwdMeasure2),
                               lbReclBwdMeasure2.Text, CheckLabelStatus(lbReclBwdMeasure2),
                               lbLeverMeasure2.Text, CheckLabelStatus(lbLeverMeasure2),
                               lbFwdDiffMeasure2.Text, lbBwdDiffMeasure2.Text,
                               lbTotalDiffMeasure2.Text, CheckLabelStatus(lbTotalDiffMeasure2));
                    wStep2++;
                    break;

                case 50:

                    if (lbReclFwdMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbReclBwdMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbLeverMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbTotalDiffMeasure2.BackColor == System.Drawing.Color.Blue)
                    {
                        PlaySound("DINGDONG.wav");
                        BarcodePrint2();
                        Logger.Log("[2] 바코드 출력");
                        GlobalValues.OkCount++;
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    else
                    {
                        BarcodePrintNg2();
                        PlaySound("NG.wav");
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    wStep2 = 51;
                    break;

                case 51:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        wStep2 = 0;
                    }
                    break;

            }

        }


