        public void Plc2WriteDbit(int startAddress, ushort[] data)
        {
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = data.Length.ToString("X2"); // 예: 32 → "20"

            // 데이터: 각 워드를 4자리 HEX로 연결
            StringBuilder hexBuilder = new StringBuilder();
            foreach (ushort word in data)
                hexBuilder.Append(word.ToString("X4"));

            // 전체 패킷 구성
            string packet = $"{(char)5}00WSB07{startAddressText}{countHex}{hexBuilder}{(char)4}";
            SerialPlc2.Write(packet);
            //Logger.Log($"[WRITE 보냄] Addr:{startAddress} Words:{data.Length} Packet:{packet}");
        }
        public void Plc2WriteD(int startAddress, int count)
        {
            int[] values = PLCData2.writePlcValue.Skip(startAddress).Take(count).ToArray();
            string hexData = string.Join("", values.Select(v => v.ToString("X4")));
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = count.ToString("X2");
            string packet = $"{(char)5}00WSB07{startAddressText}{countHex}{hexData}{(char)4}";
            SerialPlc2.Write(packet);
        }
        public static ushort[] Plc2GetWriteWords()
        {
            ushort[] words = new ushort[32]; // D4000~D4031

            for (int w = 0; w < 32; w++)
            {
                ushort word = 0;
                for (int b = 0; b < 16; b++)
                {
                    if (PLCData2.writePlcValueBit[w, b])
                        word |= (ushort)(1 << b);
                }
                words[w] = word;
            }

            return words;
        }
        private void Plc2StartWorkThread()
        {
            Plc2WorkThread = new Thread(() =>
            {
                while (Plc2isRunning)
                {
                    if (SerialPlc2.IsOpen && Plc2RequestReadyPlc)
                    {
                        Plc2RequestReadyPlc = false;
                        Plc2currentIsWrite = false;

                        if (Plc2rwStep == 0)
                        {
                            int cycleTime = (int)(DateTime.Now - Plc2cycleStartTime).TotalMilliseconds;
                            Plc2cycleStartTime = DateTime.Now;
                            LbCycle2.Invoke((MethodInvoker)(() =>
                            {
                                LbCycle2.Text = $"Cycle: {cycleTime} ms";
                            }));
                        }

                        switch (Plc2rwStep)
                        {
                            case 0:
                                Plc2currentRequestAddress = 4000;
                                Plc2ReadD(Plc2currentRequestAddress, 32);
                                break;

                            case 1:
                                ushort[] wordsToSend = Plc2GetWriteWords();
                                Plc2WriteDbit(4000, wordsToSend);
                                break;

                            case 2:
                                Plc2currentRequestAddress = 5000;
                                Plc2ReadD(Plc2currentRequestAddress, 16);
                                break;

                            case 3:
                                Plc2currentRequestAddress = 5000;
                                Plc2WriteD(Plc2currentRequestAddress, 16);
                                break;

                            case 4:
                                Plc2currentRequestAddress = 6000;
                                Plc2WriteD(Plc2currentRequestAddress, 32);
                                break;

                            case 5:
                                Plc2currentRequestAddress = 6032;
                                Plc2WriteD(Plc2currentRequestAddress, 32);
                                break;

                        }


                        if (PLCData2.FlagRecvAll == true)
                        {
                            Plc2rwStep = (Plc2rwStep + 1) % 6;
                        }
                        else
                        {
                            Plc2rwStep = (Plc2rwStep == 0) ? 1 : 0;
                        }
                    }

                    Thread.Sleep(1);
                }
            });

            Plc2WorkThread.IsBackground = true;
            Plc2WorkThread.Start();
        }
        private void Plc2StartReceiveThread()
        {
            Plc2ReceiveThread = new Thread(() =>
            {
                while (Plc2isRunning)
                {
                    try
                    {
                        if (SerialPlc2.IsOpen && SerialPlc2.BytesToRead > 0)
                        {
                            char ch = (char)SerialPlc2.ReadChar();
                            Plc2receiveBuffer.Append(ch);

                            if (ch == (char)3) // ETX
                            {
                                string fullPacket = Plc2receiveBuffer.ToString();
                                Plc2receiveBuffer.Clear();
                                //Logger.Log($"[RECV] {(fullPacket)}");
                                Plc2ProcessPlcPacket(fullPacket);
                            }
                        }
                        else
                        {
                            Thread.Sleep(1);
                        }
                    }
                    catch (Exception ex)
                    {
                        Logger.Log("[에러] 수신 쓰레드: " + ex.Message);
                    }
                }
            });

            Plc2ReceiveThread.IsBackground = true;
            Plc2ReceiveThread.Start();
        }
        private void Plc2ProcessPlcPacket(string packet)
        {
            if (packet.Contains("00RSB"))
            {
                Plc2ParsePlcResponse(packet, Plc2currentRequestAddress);
            }
            else if (packet.Contains("00WSB"))
            {
                //Logger.Log($"[WRITE 응답] D{Plc2currentRequestAddress} 쓰기 완료 ✅");

                // 쓰기 성공 시 기준값 갱신
                for (int i = 0; i < 16; i++)
                {
                    PLCData2.lastWriteBuffer[Plc2currentRequestAddress + i] = PLCData2.PlcValue[Plc2currentRequestAddress + i];
                }
            }

            Plc2RequestReadyPlc = true;
        }
        private void Plc2ParsePlcResponse(string response, int startAddress)
        {
            try
            {
                // 제어 문자 제거 (ACK, ETX)
                response = response.Replace(((char)6).ToString(), "").Replace(((char)3).ToString(), "");

                int startIndex = response.IndexOf("00RSB");
                if (startIndex == -1)
                {
                    Logger.Log("[경고] '00RSB' 없음");
                    return;
                }

                // 데이터 시작 위치
                int dataStart = startIndex + 9; // "00RSB06%" 이후부터
                int dataLength = response.Length - dataStart;
                int wordCount = dataLength / 4;

                for (int i = 0; i < wordCount; i++)
                {
                    int addr = startAddress + i;
                    string hex = response.Substring(dataStart + (i * 4), 4);
                    ushort word = Convert.ToUInt16(hex, 16);

                    if (addr >= 4000 && addr <= 4031)
                    {
                        // D4000~4031 → 비트로 저장
                        int wordIndex = addr - 4000;
                        for (int bit = 0; bit < 16; bit++)
                        {
                            PLCData2.PlcValueBit[wordIndex, bit] = ((word >> bit) & 1) == 1;
                        }
                    }
                    else
                    {
                        // 병합 대상인 경우
                        if (i + 1 < wordCount)
                        {
                            string hexLow = response.Substring(dataStart + (i * 4), 4);       // 하위
                            string hexHigh = response.Substring(dataStart + ((i + 1) * 4), 4); // 상위

                            string hex32 = hexHigh + hexLow; // 상 + 하
                            int value32 = Convert.ToInt32(hex32, 16);

                            PLCData2.PlcValue[addr] = value32;
                            PLCData2.PlcValue[addr + 1] = 0; // 상위 워드는 무시
                            //Logger.Log($"[32비트 병합] D{addr}/{addr + 1} → {value32}");
                            i++; // 2워드 소비
                            continue;
                        }
                        else
                        {
                            Logger.Log($"[경고] D{addr} 병합 실패: 워드 부족");
                            break;
                        }
                    }

                }
            }
            catch (Exception ex)
            {
                Logger.Log("[에러] 파싱 실패: " + ex.Message);
            }
        }

