            string RS = "_1e";
            string GS = "_1d";
            string EOT = "_04";

            tTmp = "[)>" + RS + "06" + GS +
                   "V2812" + GS +
                   "P" + lbLPartNo1.Text.Replace("-", "") + GS +
                   "S" + "" + GS +
                   "E" + "" + GS +
                   "T" + DateTime.Now.ToString("yyMMdd") + "D600" + "A" + Lot1 + GS +
                   "M" + "" + GS +
                   "C" + "" + GS + RS + EOT;

