            SerialPrinter.Write("^XA");
            SerialPrinter.Write("^FO40,60^BY5^BXN,6,200,,,,^FH^FD" + tTmp + "^FS");
            SerialPrinter.Write("^FO220,80^A0N,38,38^FD" + lbLPartNo1.Text + "^FS");
