        private void StartDiffLog1()
        {
            try
            {
                string logDir = Path.Combine(Application.StartupPath, "DiffLog");
                if (!Directory.Exists(logDir))
                {
                    Directory.CreateDirectory(logDir);
                }

                string fileName = DateTime.Now.ToString("yyyyMMdd_HHmmss") + "_INNER.csv";
                diffLogPath1 = Path.Combine(logDir, fileName);

                diffLogWriter1 = new StreamWriter(diffLogPath1, false, Encoding.UTF8);
                diffLogWriter1.WriteLine("Time,Step,LVDT,Torque,X,Y,Direction");
                Logger.Log($"[1] 유격 로그 시작: {diffLogPath1}");
            }
            catch (Exception ex)
            {
                Logger.Log($"[1] 유격 로그 시작 오류: {ex.Message}");
            }
        }

        /// <summary>
        /// 유격 로그 기록 (INNER/1축)
        /// </summary>
        private void WriteDiffLog1(double step, string direction)
        {
            try
            {
                if (diffLogWriter1 != null)
                {
                    double lvdt = MeasureData1.ValueLvdt;
                    double torque = MeasureData1.ValueReclTq;
                    double x = lvdt - DiffStartTmp1_1;
                    double y = tmpNum1 * torque; // 그래프에 그려지는 Y값 (상하 반전 제거)

                    string line = $"{DateTime.Now:HH:mm:ss.fff},{step},{lvdt:F4},{torque:F4},{x:F4},{y:F4},{direction}";
                    diffLogWriter1.WriteLine(line);
                    diffLogWriter1.Flush();
                }
            }
            catch (Exception ex)
            {
                Logger.Log($"[1] 유격 로그 기록 오류: {ex.Message}");
            }
        }

