        #region "LVDT"

        private readonly StringBuilder _rxBufLvdt1 = new StringBuilder(256);
        private readonly StringBuilder _rxBufLvdt2 = new StringBuilder(256);
        private System.Timers.Timer _recallTimer;

        private void InitSerial(SerialPort sp)
        {
            sp.NewLine = "\r";
            sp.ReadTimeout = 50;
            sp.WriteTimeout = 50;
            sp.ReceivedBytesThreshold = 1;
        }

        private void StartRecallPolling()
        {
            if (_recallTimer != null) return;
            _recallTimer = new System.Timers.Timer(100); // 10 Hz 시도
            _recallTimer.AutoReset = true;
            _recallTimer.Elapsed += OnRecallTimerElapsed;
            _recallTimer.Start();
        }

        private void OnRecallTimerElapsed(object sender, System.Timers.ElapsedEventArgs e)
        {
            TrySendRecall(SerialLvdt1);
            TrySendRecall(SerialLvdt2);
        }

        private void TrySendRecall(SerialPort sp)
        {
            if (sp == null || !sp.IsOpen) return;
            // 버퍼가 막히지 않았을 때만 쏘자
            if (sp.BytesToWrite == 0)
            {
                // CR + RECALL + CR
                sp.Write("\rRECALL\r");
            }
        }

        private void SerialLvdt_DataReceived(object sender, SerialDataReceivedEventArgs e)
        {
            var sp = sender as SerialPort;
            if (sp == null) return;

            try
            {
                string chunk = sp.ReadExisting();
                if (string.IsNullOrEmpty(chunk)) return;

                StringBuilder buf = ReferenceEquals(sp, SerialLvdt1) ? _rxBufLvdt1 : _rxBufLvdt2;
                buf.Append(chunk);

                // CR(0x0D)을 프레임 구분자로 사용
                ParseFrames(sp, buf);
            }
            catch
            {
                // 통신 찌꺼기 무시
            }
        }
        private void ParseFrames(SerialPort sp, StringBuilder buf)
        {
            int cr;
            while ((cr = IndexOfCr(buf)) >= 0)
            {
                // 한 프레임 추출 (CR 제외)
                string frame = buf.ToString(0, cr);
                // 버퍼에서 프레임+CR 제거
                buf.Remove(0, cr + 1);

                if (string.IsNullOrEmpty(frame)) continue;

                // 선두 ENQ(0x05) 제거
                if (frame.Length > 0 && frame[0] == '\u0005')
                    frame = frame.TrimStart('\u0005');

                // CSV 파싱
                string[] parts = frame.Split(',');
                if (parts.Length > 2)
                {
                    double val;
                    if (double.TryParse(parts[2], out val))
                    {
                        if (ReferenceEquals(sp, SerialLvdt1))
                        {
                            MeasureData1.ValueLvdt = val;
                            UpdateLvdtValue(srcLvdt1, val);
                        }
                        else if (ReferenceEquals(sp, SerialLvdt2))
                        {
                            MeasureData2.ValueLvdt = val;
                            UpdateLvdtValue(srcLvdt2, val);
                        }
                    }
                }
            }
        }

        private static int IndexOfCr(StringBuilder sb)
        {
            for (int i = 0; i < sb.Length; i++)
                if (sb[i] == '\r') return i;
            return -1;
        }

