        private void StartDiffLog1()
        {
            try
            {
                string logDir = Path.Combine(Application.StartupPath, "DiffLog");
                if (!Directory.Exists(logDir))
                {
                    Directory.CreateDirectory(logDir);
                }

                string fileName = DateTime.Now.ToString("yyyyMMdd_HHmmss") + "_INNER.csv";
                diffLogPath1 = Path.Combine(logDir, fileName);

