        private void StyleControls()
        {
            System.Drawing.Color darkBack = ColorTranslator.FromHtml("#1E1E2F");
            System.Drawing.Color darkPanel = ColorTranslator.FromHtml("#2A2A3C");
            System.Drawing.Color mint = ColorTranslator.FromHtml("#00ACC1");
            System.Drawing.Color lightMint = ColorTranslator.FromHtml("#80DEEA");
            System.Drawing.Color softPanelBlue = ColorTranslator.FromHtml("#4DD0E1");
            System.Drawing.Color resultGray = System.Drawing.Color.Gainsboro;

            this.BackColor = darkBack;
            panel4.BackColor = darkPanel;
            panel5.BackColor = darkBack;

            // Label 스타일
            label1.ForeColor = System.Drawing.Color.White;

            // Count 영역 스타일
            lbOkCount.BackColor = lightMint;
            lbNGCount.BackColor = lightMint;
            lbTotalCount.BackColor = lightMint;
            lbOkCount.ForeColor = System.Drawing.Color.Black;
            lbNGCount.ForeColor = System.Drawing.Color.Black;
            lbTotalCount.ForeColor = System.Drawing.Color.Black;

            // 로그 영역
            srcTxtLog.BackColor = System.Drawing.Color.FromArgb(40, 40, 50);
            srcTxtLog.ForeColor = System.Drawing.Color.White;

            // 버튼 스타일 통일화
            foreach (var ctrl in tableLayoutPanel1.Controls)
            {
                if (ctrl is System.Windows.Forms.Button btn)
                {
                    btn.BackColor = mint;
                    btn.ForeColor = System.Drawing.Color.White;
                    btn.FlatStyle = FlatStyle.Flat;
