                    }
                    break;

                case 37.3: // 알람 해제 확인
                    if (PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false)
                    {
                        WriteDiffLog2(37.3, "ALARM_CLEARED");
                        tmrWatch2.Restart();
                        wStep2 = 37.4; // 딜레이 후 CCW 복귀
                    }
                    else
                    {
                        WriteDiffLog2(37.3, "ALARM_STILL_ON");
                        wStep2 = 37.1; // 알람 아직 있으면 다시 리셋
                    }
                    break;

                case 37.4: // CCW 복귀 전 딜레이 (1초 대기)
                    WriteDiffLog2(37.4, "CCW_RETURN_DELAY");
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        Logger.Log("[2] CCW 복귀 딜레이 완료");
                        WriteDiffLog2(37.4, "CCW_RETURN_DELAY_END");
                        wStep2 = 37.5;
                    }
                    break;

                case 37.5: // CCW 복귀 측정 시작 (토크 0까지)
                    Logger.Log("[2] CCW 복귀 측정 시작");
                    WriteDiffLog2(37.5, "CCW_RETURN_START");
                    WriteDebugLog2(37.5, "CCW_RETURN_START");
                    PLCData2.SetPlcBit(9, 6, true);  // 1축 수동 ON
                    WriteDiffLog2(37.5, "PLC_MANUAL_ON");
                    PLCData2.SetPlcBit(9, 7, false); // 1축 수동 정지 지령 해제
                    WriteDiffLog2(37.5, "PLC_STOP_OFF");
                    PLCData2.SetPlcBit(9, 1, false); // 1축 CW OFF
                    WriteDiffLog2(37.5, "PLC_CW_OFF");
                    PLCData2.SetPlcBit(9, 2, true);  // 1축 CCW ON
                    WriteDiffLog2(37.5, "PLC_CCW_ON");
                    // diff2CwEndX, diff2CwEndLvdt는 case 35 CW_END에서 이미 저장됨
                    // 복귀선 첫 점을 CW 마지막 좌표에 찍어서 연결
                    ClassZedGraph.DrawGraphLine(PlotDiff2, diff2LastX, diff2LastY, 2);
                    tmrWatch2.Restart();
                    wStep2 = 37.6;
                    break;

                case 37.6: // CCW 복귀 - 토크 0까지 이동
                    {
                        double xReturn = diff2CwEndX + (MeasureData2.ValueLvdt - diff2CwEndLvdt);
                        double yReturn = tmpNum2 * MeasureData2.ValueReclTq; // * -1 제거 (CW 토크가 마이너스이므로)

                        // 토크가 음수(CW방향)일 때만 복귀 곡선 그리기
                        if (yReturn <= 0)
                        {
                            ClassZedGraph.DrawGraphLine(PlotDiff2, xReturn, yReturn, 2); // 파랑 선 (복귀)
                            diff2LastX = xReturn;
                            diff2LastY = yReturn;
                        }
                        WriteDiffLog2(37.6, "CCW_RETURN_MEASURE");
                        WriteDebugLog2(37.6, "CCW_RETURN_MEASURE", xReturn, yReturn);

                        // 토크가 0 근처에 도달하면 완료
                        if (Math.Abs(MeasureData2.ValueReclTq) < 0.5)
                        {
                            ClassZedGraph.DrawGraphLine(PlotDiff2, 0, 0, 2); // 그래프 원점으로 루프 닫기
                            Logger.Log("[2] CCW 복귀 완료 (토크 0 도달)");
                            WriteDiffLog2(37.6, "CCW_RETURN_END");
                            PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                            WriteDiffLog2(37.6, "PLC_CCW_OFF");
                            PLCData2.SetPlcBit(9, 7, true);  // 수동 정지
                            WriteDiffLog2(37.6, "PLC_STOP_ON");
                            CloseDiffLog2();
                            CloseDebugLog2();
                            wStep2 = 38;
                        }
                        // 타임아웃: 15초 내 토크 0 미도달 시 강제 완료
                        else if (tmrWatch2.Elapsed.TotalSeconds > 15)
                        {
                            Logger.Log("[2] CCW 복귀 타임아웃 - 강제 완료");
                            WriteDiffLog2(37.6, "CCW_RETURN_TIMEOUT");
                            WriteDebugLog2(37.6, "CCW_RETURN_TIMEOUT", xReturn, yReturn);
                            PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                            PLCData2.SetPlcBit(9, 7, true);  // 수동 정지
                            CloseDiffLog2();
                            CloseDebugLog2();
                            wStep2 = 38;
                        }
                    }
                    break;

                case 38:
                    // 속도 복원 (원래 속도로)
                    WriteDiffLog2(38, $"SPEED_RESTORE: BeforeSpeed={tmpBeforeSpeed2}, CurrentSpd={PLCData2.Servo1JogSpd}");
                    PLCData2.Servo1JogSpd = tmpBeforeSpeed2;
                    PLCData2.FlagRecvAll = true;
                    PLCData2.ServoSet();

                    PLCData2.SetPlcBit(9, 7, false); //1축 수동 정지 지령
                    PLCData2.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData2.SetPlcBit(11, 5, true); //2축 자동 ON
                    PLCData2.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData2.SetPlcBit(11, 6, false); //2축 수동 OFF
                    _csv2.Save($"{tmpsave2}_Diff");
                    wStep2++;
                    break;

                case 39:
                    Logger.Log("[2] LVDT 후진 시작");
                    PLCData2.SetPlcBit(4, 13, true); //LVDT 후진
                    wStep2++;
                    break;

                case 40:
                    if (PLCData2.PlcValueBit[0, 11] == true) //후진 확인
                    {
                        Logger.Log("[2] LVDT 후진 완료");
                        PLCData2.SetPlcBit(4, 13, false);
                        PLCData2.FlagRecvAll = false;
                        wStep2++;
                    }
                    break;

                case 41:
                    Logger.Log("[2] 2축 2번 포지션 이동 시작");
                    PLCData2.SetPlcBit(13, 1, true); //2축 2번 포지션,레버 해제
                    wStep2++;
                    break;

                case 42:
                    if (PLCData2.PlcValueBit[15, 1] == true)
                    {
                        Logger.Log("[2] 2축 2번 포지션 이동 완료");
                        PLCData2.SetPlcBit(13, 1, false); //레버 해제 완료
                        wStep2++;
                    }
                    break;

                case 43:
                    Logger.Log("[2] 1축 1번 포지션 이동 시작");
                    PLCData2.SetPlcBit(12, 0, true); //1축 1번 포지션
                    wStep2++;
                    break;

                case 44:
                    if (PLCData2.PlcValueBit[14, 0] == true)
                    {
                        Logger.Log("[2] 1축 1번 포지션 이동 완료");
                        PLCData2.SetPlcBit(12, 0, false);
                        wStep2++;
                    }
                    break;

                case 45:
                    Logger.Log("[2] 2축 1번 포지션 이동 시작");
                    PLCData2.SetPlcBit(13, 0, true); //2축 1번 포지션,레버 원위치
                    wStep2++;
                    break;

                case 46:
                    if (PLCData2.PlcValueBit[15, 0] == true)
                    {
                        Logger.Log("[2] 2축 1번 포지션 이동 완료");
                        PLCData2.SetPlcBit(13, 0, false); //레버 해제 완료
                        wStep2++;
                    }
                    break;

                case 47:

                    Logger.Log("[2] 클램프 해제");
                    PLCData2.SetPlcBit(4, 9, true); //클램프 상승
                    PLCData2.SetPlcBit(4, 10, true); //클램프 후진
                    tmrRstWatch2.Restart();
                    wStep2++;
                    break;

                case 48:
                    if (PLCData2.PlcValueBit[0, 6] == true) //클램프 상승
                    {
                        PLCData2.SetPlcBit(4, 9, false); //클램프 상승
                    }
                    if (PLCData2.PlcValueBit[0, 8] == true) //클램프 후진
                    {
                        PLCData2.SetPlcBit(4, 10, false); //클램프 후진
                    }
                    if (PLCData2.PlcValueBit[0, 6] == true && PLCData2.PlcValueBit[0, 8] == true)
                    {
                        wStep2++;
                    }
                    break;

                case 49:
                    Logger.Log("[2] 데이터 저장");
                    InsertData(lbBarcode2.Text, lbLPartNo2.Text,
                               lbReclFwdMeasure2.Text, CheckLabelStatus(lbReclFwdMeasure2),
                               lbReclBwdMeasure2.Text, CheckLabelStatus(lbReclBwdMeasure2),
                               lbLeverMeasure2.Text, CheckLabelStatus(lbLeverMeasure2),
                               lbFwdDiffMeasure2.Text, lbBwdDiffMeasure2.Text,
                               lbTotalDiffMeasure2.Text, CheckLabelStatus(lbTotalDiffMeasure2));
                    wStep2++;
                    break;

                case 50:

                    if (lbReclFwdMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbReclBwdMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbLeverMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbTotalDiffMeasure2.BackColor == System.Drawing.Color.Blue)
                    {
                        PlaySound("DINGDONG.wav");
                        BarcodePrint2();
                        Logger.Log("[2] 바코드 출력");
                        GlobalValues.OkCount++;
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    else
                    {
                        BarcodePrintNg2();
                        PlaySound("NG.wav");
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    wStep2 = 51;
                    break;

                case 51:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        wStep2 = 0;
                    }
                    break;

            }

        }


        public string CheckLabelStatus(System.Windows.Forms.Label lbl)
        {
            if (lbl.BackColor == System.Drawing.Color.Blue)
                return "OK";
            else
                return "NG";
        }

        private void tmrFlikerTimer_Tick(object sender, EventArgs e)
        {
            if (PLCData1.PlcValueBit[9, 0] == true)
            {
                PLCData1.SetPlcBit(9, 0, false);
                PLCData1.SetPlcBit(11, 0, false);
            }
            else
            {
                PLCData1.SetPlcBit(9, 0, true);
                PLCData1.SetPlcBit(11, 0, true);
            }
            if (PLCData2.PlcValueBit[9, 0] == true)
            {
                PLCData2.SetPlcBit(9, 0, false);
                PLCData2.SetPlcBit(11, 0, false);
            }
            else
            {
                PLCData2.SetPlcBit(9, 0, true);
                PLCData2.SetPlcBit(11, 0, true);
            }
        }

        #region "Plc1"

        public void Plc1ReadD(int startAddress, int count)
        {
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = count.ToString("X2");
            string packet = $"{(char)5}00RSB07{startAddressText}{countHex}{(char)4}";
            SerialPlc1.Write(packet);
        }
        public void Plc1WriteDbit(int startAddress, ushort[] data)
        {
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = data.Length.ToString("X2"); // 예: 32 → "20"

            // 데이터: 각 워드를 4자리 HEX로 연결
            StringBuilder hexBuilder = new StringBuilder();
            foreach (ushort word in data)
                hexBuilder.Append(word.ToString("X4"));

            // 전체 패킷 구성
            string packet = $"{(char)5}00WSB07{startAddressText}{countHex}{hexBuilder}{(char)4}";
            SerialPlc1.Write(packet);
            //Logger.Log($"[WRITE 보냄] Addr:{startAddress} Words:{data.Length} Packet:{packet}");
        }
        public void Plc1WriteD(int startAddress, int count)
        {
            int[] values = PLCData1.writePlcValue.Skip(startAddress).Take(count).ToArray();
            string hexData = string.Join("", values.Select(v => v.ToString("X4")));
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = count.ToString("X2");
            string packet = $"{(char)5}00WSB07{startAddressText}{countHex}{hexData}{(char)4}";
            SerialPlc1.Write(packet);
        }

        public static ushort[] Plc1GetWriteWords()
        {
            ushort[] words = new ushort[32]; // D4000~D4031

            for (int w = 0; w < 32; w++)
            {
                ushort word = 0;
                for (int b = 0; b < 16; b++)
                {
                    if (PLCData1.writePlcValueBit[w, b])
                        word |= (ushort)(1 << b);
                }
                words[w] = word;
            }

            return words;
        }
        private void Plc1StartWorkThread()
        {
            Plc1WorkThread = new Thread(() =>
            {
                while (Plc1isRunning)
                {
                    if (SerialPlc1.IsOpen && Plc1RequestReadyPlc)
                    {
                        Plc1RequestReadyPlc = false;
                        Plc1currentIsWrite = false;

                        if (Plc1rwStep == 0)
                        {
                            int cycleTime = (int)(DateTime.Now - Plc1cycleStartTime).TotalMilliseconds;
                            Plc1cycleStartTime = DateTime.Now;
                            LbCycle1.Invoke((MethodInvoker)(() =>
                            {
                                LbCycle1.Text = $"Cycle: {cycleTime} ms";
                            }));
                        }

                        switch (Plc1rwStep)
                        {
                            case 0:
                                Plc1currentRequestAddress = 4000;
                                Plc1ReadD(Plc1currentRequestAddress, 32);
                                break;

                            case 1:
                                ushort[] wordsToSend = Plc1GetWriteWords();
                                Plc1WriteDbit(4000, wordsToSend);
                                break;

                            case 2:
                                Plc1currentRequestAddress = 5000;
                                Plc1ReadD(Plc1currentRequestAddress, 16);
                                break;

                            case 3:
                                Plc1currentRequestAddress = 5000;
                                Plc1WriteD(Plc1currentRequestAddress, 16);
                                break;

                            case 4:
                                Plc1currentRequestAddress = 6000;
                                Plc1WriteD(Plc1currentRequestAddress, 32);
                                break;

                            case 5:
                                Plc1currentRequestAddress = 6032;
                                Plc1WriteD(Plc1currentRequestAddress, 32);
                                break;
                        }


                        if (PLCData1.FlagRecvAll == true)
                        {
                            Plc1rwStep = (Plc1rwStep + 1) % 6;
                        }
                        else
                        {
                            Plc1rwStep = (Plc1rwStep == 0) ? 1 : 0;
                        }
                    }

                    Thread.Sleep(1);
                }
            });

            Plc1WorkThread.IsBackground = true;
            Plc1WorkThread.Start();
        }
        private void Plc1StartReceiveThread()
        {
            Plc1ReceiveThread = new Thread(() =>
            {
                while (Plc1isRunning)
                {
                    try
                    {
                        if (SerialPlc1.IsOpen && SerialPlc1.BytesToRead > 0)
                        {
                            char ch = (char)SerialPlc1.ReadChar();
                            Plc1receiveBuffer.Append(ch);

                            if (ch == (char)3) // ETX
                            {
                                string fullPacket = Plc1receiveBuffer.ToString();
                                Plc1receiveBuffer.Clear();
                                //Logger.Log($"[RECV] {(fullPacket)}");
                                Plc1ProcessPlcPacket(fullPacket);
                            }
                        }
                        else
                        {
                            Thread.Sleep(1);
                        }
                    }
                    catch (Exception ex)
                    {
                        Logger.Log("[에러] 수신 쓰레드: " + ex.Message);
                    }
                }
            });

            Plc1ReceiveThread.IsBackground = true;
            Plc1ReceiveThread.Start();
        }
        private void Plc1ProcessPlcPacket(string packet)
        {
            if (packet.Contains("00RSB"))
            {
                Plc1ParsePlcResponse(packet, Plc1currentRequestAddress);
            }
            else if (packet.Contains("00WSB"))
            {
                //Logger.Log($"[WRITE 응답] D{Plc1currentRequestAddress} 쓰기 완료 ✅");

                // 쓰기 성공 시 기준값 갱신
                for (int i = 0; i < 16; i++)
                {
                    PLCData1.lastWriteBuffer[Plc1currentRequestAddress + i] = PLCData1.PlcValue[Plc1currentRequestAddress + i];
                }
            }

            Plc1RequestReadyPlc = true;
        }
        private void Plc1ParsePlcResponse(string response, int startAddress)
        {
            try
            {
                // 제어 문자 제거 (ACK, ETX)
                response = response.Replace(((char)6).ToString(), "").Replace(((char)3).ToString(), "");

                int startIndex = response.IndexOf("00RSB");
                if (startIndex == -1)
                {
                    Logger.Log("[경고] '00RSB' 없음");
                    return;
                }

                // 데이터 시작 위치
                int dataStart = startIndex + 9; // "00RSB06%" 이후부터
                int dataLength = response.Length - dataStart;
                int wordCount = dataLength / 4;

                for (int i = 0; i < wordCount; i++)
                {
                    int addr = startAddress + i;
                    string hex = response.Substring(dataStart + (i * 4), 4);
                    ushort word = Convert.ToUInt16(hex, 16);

                    if (addr >= 4000 && addr <= 4031)
                    {
                        // D4000~4031 → 비트로 저장
                        int wordIndex = addr - 4000;
                        for (int bit = 0; bit < 16; bit++)
                        {
                            PLCData1.PlcValueBit[wordIndex, bit] = ((word >> bit) & 1) == 1;
                            //Logger.Log($"[비트 획득 완료] D{addr}");
                        }
                    }
                    else
                    {
                        // 병합 대상인 경우
                        if (i + 1 < wordCount)
                        {
                            string hexLow = response.Substring(dataStart + (i * 4), 4);       // 하위
                            string hexHigh = response.Substring(dataStart + ((i + 1) * 4), 4); // 상위

                            string hex32 = hexHigh + hexLow; // 상 + 하
                            int value32 = Convert.ToInt32(hex32, 16);

                            PLCData1.PlcValue[addr] = value32;
                            PLCData1.PlcValue[addr + 1] = 0; // 상위 워드는 무시
                            //Logger.Log($"[32비트 병합] D{addr}/{addr + 1} → {value32}");
                            i++; // 1 워드 소비
                            continue;
                        }
                        else
                        {
                            Logger.Log($"[경고] D{addr} 병합 실패: 워드 부족");
                            break;
                        }
                    }

                }
            }
            catch (Exception ex)
            {
                Logger.Log("[에러] 파싱 실패: " + ex.Message);
            }
        }

