        #region "Plc1"

        public void Plc1ReadD(int startAddress, int count)
        {
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = count.ToString("X2");
            string packet = $"{(char)5}00RSB07{startAddressText}{countHex}{(char)4}";
            SerialPlc1.Write(packet);
        }
        public void Plc1WriteDbit(int startAddress, ushort[] data)
        {
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = data.Length.ToString("X2"); // 예: 32 → "20"

            // 데이터: 각 워드를 4자리 HEX로 연결
            StringBuilder hexBuilder = new StringBuilder();
            foreach (ushort word in data)
                hexBuilder.Append(word.ToString("X4"));

            // 전체 패킷 구성
            string packet = $"{(char)5}00WSB07{startAddressText}{countHex}{hexBuilder}{(char)4}";
            SerialPlc1.Write(packet);
            //Logger.Log($"[WRITE 보냄] Addr:{startAddress} Words:{data.Length} Packet:{packet}");
        }
        public void Plc1WriteD(int startAddress, int count)
        {
            int[] values = PLCData1.writePlcValue.Skip(startAddress).Take(count).ToArray();
            string hexData = string.Join("", values.Select(v => v.ToString("X4")));
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = count.ToString("X2");
            string packet = $"{(char)5}00WSB07{startAddressText}{countHex}{hexData}{(char)4}";
            SerialPlc1.Write(packet);
        }

        public static ushort[] Plc1GetWriteWords()
        {
            ushort[] words = new ushort[32]; // D4000~D4031

            for (int w = 0; w < 32; w++)
            {
                ushort word = 0;
                for (int b = 0; b < 16; b++)
                {
                    if (PLCData1.writePlcValueBit[w, b])
                        word |= (ushort)(1 << b);
                }
                words[w] = word;
            }

            return words;
        }
        private void Plc1StartWorkThread()
        {
            Plc1WorkThread = new Thread(() =>
            {
                while (Plc1isRunning)
                {
                    if (SerialPlc1.IsOpen && Plc1RequestReadyPlc)
                    {
                        Plc1RequestReadyPlc = false;
                        Plc1currentIsWrite = false;

                        if (Plc1rwStep == 0)
                        {
                            int cycleTime = (int)(DateTime.Now - Plc1cycleStartTime).TotalMilliseconds;
                            Plc1cycleStartTime = DateTime.Now;
                            LbCycle1.Invoke((MethodInvoker)(() =>
                            {
                                LbCycle1.Text = $"Cycle: {cycleTime} ms";
                            }));
                        }

                        switch (Plc1rwStep)
                        {
                            case 0:
                                Plc1currentRequestAddress = 4000;
                                Plc1ReadD(Plc1currentRequestAddress, 32);
                                break;

                            case 1:
                                ushort[] wordsToSend = Plc1GetWriteWords();
                                Plc1WriteDbit(4000, wordsToSend);
                                break;

                            case 2:
                                Plc1currentRequestAddress = 5000;
                                Plc1ReadD(Plc1currentRequestAddress, 16);
                                break;

                            case 3:
                                Plc1currentRequestAddress = 5000;
                                Plc1WriteD(Plc1currentRequestAddress, 16);
                                break;

                            case 4:
                                Plc1currentRequestAddress = 6000;
                                Plc1WriteD(Plc1currentRequestAddress, 32);
                                break;

                            case 5:
                                Plc1currentRequestAddress = 6032;
                                Plc1WriteD(Plc1currentRequestAddress, 32);
                                break;
                        }


                        if (PLCData1.FlagRecvAll == true)
                        {
                            Plc1rwStep = (Plc1rwStep + 1) % 6;
                        }
                        else
                        {
                            Plc1rwStep = (Plc1rwStep == 0) ? 1 : 0;
                        }
                    }

                    Thread.Sleep(1);
                }
            });

            Plc1WorkThread.IsBackground = true;
            Plc1WorkThread.Start();
        }
        private void Plc1StartReceiveThread()
        {
            Plc1ReceiveThread = new Thread(() =>
            {
                while (Plc1isRunning)
                {
                    try
                    {
                        if (SerialPlc1.IsOpen && SerialPlc1.BytesToRead > 0)
                        {
                            char ch = (char)SerialPlc1.ReadChar();
                            Plc1receiveBuffer.Append(ch);

                            if (ch == (char)3) // ETX
                            {
                                string fullPacket = Plc1receiveBuffer.ToString();
                                Plc1receiveBuffer.Clear();
                                //Logger.Log($"[RECV] {(fullPacket)}");
                                Plc1ProcessPlcPacket(fullPacket);
                            }
                        }
                        else
                        {
                            Thread.Sleep(1);
                        }
                    }
                    catch (Exception ex)
                    {
                        Logger.Log("[에러] 수신 쓰레드: " + ex.Message);
                    }
                }
            });

            Plc1ReceiveThread.IsBackground = true;
            Plc1ReceiveThread.Start();
        }
        private void Plc1ProcessPlcPacket(string packet)
        {
            if (packet.Contains("00RSB"))
            {
                Plc1ParsePlcResponse(packet, Plc1currentRequestAddress);
            }
            else if (packet.Contains("00WSB"))
            {
                //Logger.Log($"[WRITE 응답] D{Plc1currentRequestAddress} 쓰기 완료 ✅");

                // 쓰기 성공 시 기준값 갱신
                for (int i = 0; i < 16; i++)
                {
                    PLCData1.lastWriteBuffer[Plc1currentRequestAddress + i] = PLCData1.PlcValue[Plc1currentRequestAddress + i];
                }
            }

            Plc1RequestReadyPlc = true;
        }
        private void Plc1ParsePlcResponse(string response, int startAddress)
        {
            try
            {
                // 제어 문자 제거 (ACK, ETX)
                response = response.Replace(((char)6).ToString(), "").Replace(((char)3).ToString(), "");

                int startIndex = response.IndexOf("00RSB");
                if (startIndex == -1)
                {
                    Logger.Log("[경고] '00RSB' 없음");
                    return;
                }

                // 데이터 시작 위치
                int dataStart = startIndex + 9; // "00RSB06%" 이후부터
                int dataLength = response.Length - dataStart;
                int wordCount = dataLength / 4;

                for (int i = 0; i < wordCount; i++)
                {
                    int addr = startAddress + i;
                    string hex = response.Substring(dataStart + (i * 4), 4);
                    ushort word = Convert.ToUInt16(hex, 16);

                    if (addr >= 4000 && addr <= 4031)
                    {
                        // D4000~4031 → 비트로 저장
                        int wordIndex = addr - 4000;
                        for (int bit = 0; bit < 16; bit++)
                        {
                            PLCData1.PlcValueBit[wordIndex, bit] = ((word >> bit) & 1) == 1;
                            //Logger.Log($"[비트 획득 완료] D{addr}");
                        }
                    }
                    else
                    {
                        // 병합 대상인 경우
                        if (i + 1 < wordCount)
                        {
                            string hexLow = response.Substring(dataStart + (i * 4), 4);       // 하위
                            string hexHigh = response.Substring(dataStart + ((i + 1) * 4), 4); // 상위

                            string hex32 = hexHigh + hexLow; // 상 + 하
                            int value32 = Convert.ToInt32(hex32, 16);

                            PLCData1.PlcValue[addr] = value32;
                            PLCData1.PlcValue[addr + 1] = 0; // 상위 워드는 무시
                            //Logger.Log($"[32비트 병합] D{addr}/{addr + 1} → {value32}");
                            i++; // 1 워드 소비
                            continue;
                        }
                        else
                        {
                            Logger.Log($"[경고] D{addr} 병합 실패: 워드 부족");
                            break;
                        }
                    }

                }
            }
            catch (Exception ex)
            {
                Logger.Log("[에러] 파싱 실패: " + ex.Message);
            }
        }

