            string RS = "_1e";
            string GS = "_1d";
            string EOT = "_04";

            tTmp = "[)>" + RS + "06" + GS +
                   "V2812" + GS +
                   "P" + lbLPartNo1.Text.Replace("-", "") + GS +
                   "S" + "" + GS +
                   "E" + "" + GS +
