                    Logger.Log($"[2] 유격 로그 저장 완료: {diffLogPath2}");
                }
            }
            catch (Exception ex)
            {
                Logger.Log($"[2] 유격 로그 종료 오류: {ex.Message}");
            }
        }

        #endregion
    }

}
